function n(d,e,s,c,l,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="alias-configuration" tabindex="-1">Alias Configuration <a class="header-anchor" href="#alias-configuration" aria-label="Permalink to &quot;Alias Configuration&quot;">​</a></h1><p>Abre archivos de configuración en tu editor por defecto con un solo comando.</p><h2 id="descubrir" tabindex="-1">Descubrir <a class="header-anchor" href="#descubrir" aria-label="Permalink to &quot;Descubrir&quot;">​</a></h2><p>Los alias configuration ofrecen atajos para abrir archivos de configuración usados con frecuencia. Estos alias se definen en <code>configuration.aliases.sh</code> y se cargan automáticamente por chezmoi.</p><p>Cada alias abre el archivo correspondiente en el editor de texto predeterminado del sistema, sin tener que recordar rutas.</p><h2 id="referencia" tabindex="-1">Referencia <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referencia&quot;">​</a></h2><h3 id="configuracion-del-shell" tabindex="-1">Configuración del shell <a class="header-anchor" href="#configuracion-del-shell" aria-label="Permalink to &quot;Configuración del shell&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th></tr></thead><tbody><tr><td><code>bshrc</code></td><td>Abrir configuración Bash (~/.bashrc)</td></tr><tr><td><code>bshp</code></td><td>Abrir perfil Bash (~/.bash_profile)</td></tr><tr><td><code>zshrc</code></td><td>Abrir configuración Zsh (~/.zshrc)</td></tr><tr><td><code>zshp</code></td><td>Abrir perfil Zsh (~/.zprofile)</td></tr></tbody></table><h3 id="control-de-versiones" tabindex="-1">Control de versiones <a class="header-anchor" href="#control-de-versiones" aria-label="Permalink to &quot;Control de versiones&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th></tr></thead><tbody><tr><td><code>gcfg</code></td><td>Abrir configuración Git (~/.gitconfig)</td></tr><tr><td><code>gign</code></td><td>Abrir archivo Git ignore (~/.gitignore)</td></tr></tbody></table><h3 id="red-y-servidores" tabindex="-1">Red y servidores <a class="header-anchor" href="#red-y-servidores" aria-label="Permalink to &quot;Red y servidores&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th></tr></thead><tbody><tr><td><code>apconf</code></td><td>Abrir configuración Apache</td></tr><tr><td><code>ngconf</code></td><td>Abrir configuración Nginx</td></tr><tr><td><code>sshconf</code></td><td>Abrir configuración SSH (~/.ssh/config)</td></tr><tr><td><code>hosts</code></td><td>Abrir archivo hosts (/etc/hosts)</td></tr></tbody></table><h3 id="herramientas-de-desarrollo" tabindex="-1">Herramientas de desarrollo <a class="header-anchor" href="#herramientas-de-desarrollo" aria-label="Permalink to &quot;Herramientas de desarrollo&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th></tr></thead><tbody><tr><td><code>dockcomp</code></td><td>Abrir un archivo Docker Compose</td></tr><tr><td><code>eddir</code></td><td>Abrir el directorio actual en el editor por defecto</td></tr></tbody></table>',14)])])}const b=a(o,[["render",n]]);export{u as __pageData,b as default};
